    }

    // Apply highly enchanted surcharge (per-item)
    for (const item of items) {
      if (item.enchantment >= ENCHANTMENT_SURCHARGE_THRESHOLD) {
        premium += BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE;
      }
